// 将语义检查结果添加为文档批注
var doc = Application.ActiveDocument;
var results = [
  {"rule": "L-001", "name": "术语一致性", "location": "第2段", "original": "砼", "suggestion": "建议统一使用“混凝土”"},
  {"rule": "L-002", "name": "模糊引用", "location": "第5段", "original": "如上图所示", "suggestion": "建议明确引用具体图表编号，例如“如图1所示”"},
  {"rule": "L-003", "name": "图表引用完整性", "location": "第7段", "original": "详细数据参见表5", "suggestion": "文档中未找到表5，请核实图表编号或补充对应图表"},
  {"rule": "L-004", "name": "繁体字检测", "location": "第9段", "original": "結構", "suggestion": "建议改为简体中文“结构”"}
];

// 遍历结果添加批注
for (var i = 0; i < results.length; i++) {
  var result = results[i];
  var commentText = "【" + result.name + "】" + result.suggestion + " (规则：" + result.rule + ")";

  // 在实际应用中，这里应该根据location定位到具体段落
  // 由于无法精确定位，这里在文档末尾添加批注作为演示
  var range = doc.Range(doc.Content.End - 1, doc.Content.End);
  range.Comments.Add(range, commentText);
}

return "已添加" + results.length + "条语义检查批注到文档中";
